import '../lib/proxy_policy.dart';
import '../lib/request_origin.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final policy = TrustedProxyPolicy(['2001:db8:4400::/40']);
  check(policy.trusts('2001:db8:44ff::12'), 'IPv6 members of a trusted range are accepted');
  check(!policy.trusts('2001:db8:4500::12'), 'adjacent IPv6 ranges remain untrusted');

  final resolver = ExternalOriginResolver(policy);
  final result = resolver.resolve(const RequestMetadata(
    remoteAddress: '2001:db8:44ff::9',
    scheme: 'http',
    host: 'gateway.internal',
    headers: {
      'x-forwarded-for': '2001:db8:9000::7, 2001:db8:4401::8',
      'x-forwarded-proto': 'https, http',
      'x-forwarded-host': 'v6.example.test, relay.internal',
    },
  ));
  check(result.clientAddress == '2001:db8:9000::7', 'IPv6 chains stop at the untrusted client');
  check(result.uri('/events').toString() ==
      'https://v6.example.test/events', 'IPv6 proxy chains retain the external origin');
}
